// Spiral Staircase — rich multi-material showcase (v6)
// Stone column with flared base · alternating walnut steps ·
// brass railing posts · connecting handrail · bronze balusters · top landing
// Right-handed, Z-up. Base sits on Z=0.
// v6: exit gap in baluster ring + partial handrail arc so the top landing
//     is actually accessible from the stairs.

const { Manifold, CrossSection } = api;

// ---------------------------------------------------------------
// Parameters
// ---------------------------------------------------------------
const stepCount     = 16;
const stepAngleDeg  = 22.5;       // 16 × 22.5 = 360° full spiral
const stepRise      = 15;         // vertical mm per step
const stepThick     = 16;         // tread slab height (> stepRise = 1mm Z overlap)
const stepInnerR    = 23;         // inner cutout radius (column is 28, so 5mm overlap)
const stepOuterR    = 118;        // tread reach from center
const stepWedgeDeg  = 32;         // wider arc = more visual mass per step

const columnR = 28;               // thicker column
const columnH = stepCount * stepRise + stepThick + 12; // ~268mm

const postR       = 4.2;          // chunky posts
const postH       = 64;           // tall for clear silhouette
const postEveryN  = 2;            // every other step → 8 posts total

const platformR = stepOuterR - 8; // 110mm — inset from steps so spiral shows
const platformH = 14;

const balusterCount = 14;
const balusterR     = 3.2;
const balusterH     = 44;         // tall, above handrail
const balusterRingR = platformR - 8;

// ---------------------------------------------------------------
// Colors — deep, rich, saturated
// ---------------------------------------------------------------
const C_STONE      = '#263645';  // dramatic deep slate-navy stone
const C_STONE_BASE = '#1e2d3a';  // even darker for base ring
const C_WALNUT_A   = '#924e28';  // rich warm walnut (lighter alternating)
const C_WALNUT_B   = '#5c2b10';  // deep espresso walnut (darker alternating)
const C_BRASS      = '#d9aa18';  // warm polished brass
const C_BRONZE     = '#a06820';  // rich bronze-amber
const C_PLATFORM   = '#7a4020';  // platform walnut (distinct from steps)
const C_HANDRAIL   = '#c89408';  // antique gold handrail

// ---------------------------------------------------------------
// 1. Central column — stone with architectural base, cap, and ring bands
// ---------------------------------------------------------------
// Main shaft
const shaft = Manifold.cylinder(columnH, columnR, columnR, 72);

// Flared base (wider foot — like a classical column plinth)
const base  = Manifold.cylinder(24, columnR * 1.85, columnR * 1.05, 72);

// Neck/capital at top
const cap   = Manifold.cylinder(16, columnR * 1.15, columnR * 0.9, 72)
  .translate([0, 0, columnH - 16]);

// Decorative ring bands — horizontal grooves break the column into registers
// Ring at ~1/3 height
const band1Outer = Manifold.cylinder(8, columnR * 1.18, columnR * 1.18, 72)
  .translate([0, 0, columnH * 0.33]);
const band1Inner = Manifold.cylinder(10, columnR * 0.95, columnR * 0.95, 72)
  .translate([0, 0, columnH * 0.33 - 1]);
const band1 = band1Outer.subtract(band1Inner);  // creates a torus-like ring

// Ring at ~2/3 height
const band2Outer = Manifold.cylinder(8, columnR * 1.18, columnR * 1.18, 72)
  .translate([0, 0, columnH * 0.66]);
const band2Inner = Manifold.cylinder(10, columnR * 0.95, columnR * 0.95, 72)
  .translate([0, 0, columnH * 0.66 - 1]);
const band2 = band2Outer.subtract(band2Inner);

const columnRaw = shaft.add(base).add(cap).add(band1).add(band2);
const column    = api.label(columnRaw, 'stone', { color: C_STONE });

// ---------------------------------------------------------------
// 2. Step prototype — wedge tread
//    The tread is thicker than the rise so adjacent steps overlap 1mm in Z,
//    ensuring a manifold union with no gaps.
// ---------------------------------------------------------------
function makeStep(isLight) {
  const halfAngle = stepWedgeDeg / 2;

  // Full disk for clipping
  const disk = Manifold.cylinder(stepThick, stepOuterR, stepOuterR, 96);

  // Wedge cuts — generous outer slab intersected with the disk
  const slab    = Manifold.cube([stepOuterR * 2.6, stepOuterR * 2.6, stepThick + 2], true)
    .translate([0, 0, stepThick / 2]);
  const cutPos  = Manifold.cube([stepOuterR * 3.2, stepOuterR * 3.2, stepThick + 4], true)
    .translate([0, stepOuterR * 1.6, stepThick / 2])
    .rotate([0, 0,  halfAngle]);
  const cutNeg  = Manifold.cube([stepOuterR * 3.2, stepOuterR * 3.2, stepThick + 4], true)
    .translate([0, -stepOuterR * 1.6, stepThick / 2])
    .rotate([0, 0, -halfAngle]);

  let wedge = slab.subtract(cutPos).subtract(cutNeg).intersect(disk);

  // Hollow out center — smaller than column so it solidly overlaps
  const hole = Manifold.cylinder(stepThick + 4, stepInnerR, stepInnerR, 48)
    .translate([0, 0, -2]);
  wedge = wedge.subtract(hole);

  const color = isLight ? C_WALNUT_A : C_WALNUT_B;
  const label = isLight ? 'treadLight' : 'treadDark';
  return api.label(wedge, label, { color });
}

// ---------------------------------------------------------------
// 3. Spiral steps — 16 alternating walnut wedges
// ---------------------------------------------------------------
const stepParts = [];
for (let i = 0; i < stepCount; i++) {
  const step = makeStep(i % 2 === 0)
    .rotate([0, 0, i * stepAngleDeg])
    .translate([0, 0, i * stepRise]);
  stepParts.push(step);
}
const steps = stepParts.reduce((a, b) => a.add(b));

// ---------------------------------------------------------------
// 4. Railing posts — brass with tapered shaft + ball cap
// ---------------------------------------------------------------
// Centered at outer edge of step
const postX = stepOuterR - 10;
const postBody = Manifold.cylinder(postH, postR * 1.4, postR * 0.85, 24)
  .translate([postX, 0, stepThick - 2]);
const postBall = Manifold.sphere(postR * 1.8, 18)
  .translate([postX, 0, stepThick - 2 + postH]);
const postProto = api.label(postBody.add(postBall), 'rail', { color: C_BRASS });
const posts = api.spiralPattern(postProto, stepCount / postEveryN, {
  anglePerCopy: stepAngleDeg * postEveryN,
  risePerCopy:  stepRise  * postEveryN,
});

// ---------------------------------------------------------------
// 5. Top landing platform — walnut disk
// ---------------------------------------------------------------
const platZ = columnH - platformH;
const platDisk = Manifold.cylinder(platformH, platformR, platformR, 96);
const platform = api.label(platDisk, 'platform', { color: C_PLATFORM })
  .translate([0, 0, platZ]);

// ---------------------------------------------------------------
// 6. Balusters — bronze, around platform perimeter
//    Exit gap centered at 0° (where top step arrives), spanning ±30° (60° total).
//    Base sunk 4mm into platform for solid overlap.
// ---------------------------------------------------------------
const EXIT_START = 330;  // degrees — gap begins here (approaching 0° from below)
const EXIT_END   = 30;   // degrees — gap ends here (30° past north)

const balZ0 = platZ - 4;
const balusterParts = [];
for (let i = 0; i < balusterCount; i++) {
  const angle = i * (360 / balusterCount);
  // Skip balusters that fall inside the exit zone (wraps around 0°)
  const inGap = (angle > EXIT_START || angle < EXIT_END);
  if (inGap) continue;
  const balShaft = Manifold.cylinder(balusterH + 4, balusterR * 1.2, balusterR * 0.75, 20)
    .translate([0, 0, balZ0]);
  const balBall = Manifold.sphere(balusterR * 1.4, 14)
    .translate([0, 0, balZ0 + balusterH + 4]);
  const balLabeled = api.label(balShaft.add(balBall), 'baluster', { color: C_BRONZE });
  balusterParts.push(balLabeled.translate([balusterRingR, 0, 0]).rotate([0, 0, angle]));
}
const balusters = Manifold.union(balusterParts);

// ---------------------------------------------------------------
// 7. Handrail arc — antique gold, 300° arc leaving a 60° exit gap
//    Arc spans from 30° to 330° (skipping the exit zone at 0°).
// ---------------------------------------------------------------
const railZ = balZ0 + balusterH + 4;   // sits right at top of balusters
const railTubeR = 3.5;
const railProfile = CrossSection.circle(railTubeR, 22)
  .translate([balusterRingR, 0]);
// revolve(segments, degreesOfRevolution) — 300° arc, 60 segments for smoothness
const handrailArc = railProfile.revolve(60, 300).translate([0, 0, railZ]);
const handrail = api.label(
  handrailArc.rotate([0, 0, 30]),  // rotate so arc spans 30° → 330°, gap at 0°
  'handrail',
  { color: C_HANDRAIL }
);

// ---------------------------------------------------------------
// 8. Assemble — must be one manifold solid
// ---------------------------------------------------------------
const stair = api.expectUnion(
  [column, steps, posts, platform, balusters, handrail],
  { expectComponents: 1 }
);

// ---------------------------------------------------------------
// 9. Surface textures — scoped by region
// ---------------------------------------------------------------

// Stone: voronoi cracked-stone look on column
api.surface.voronoi({
  amplitude: 1.0,
  cellSize:  12,
  wallWidth: 0.18,
  raised:    true,
  quality:   0.6,
  label:     'stone',
});

// Walnut steps: woven wood-grain texture
api.surface.woven({
  amplitude:      0.22,
  threadSpacing:  3.2,
  threadWidth:    0.52,
  underDepth:     0.38,
  quality:        0.55,
  label:          'treadLight',
});
api.surface.woven({
  amplitude:      0.22,
  threadSpacing:  3.2,
  threadWidth:    0.52,
  underDepth:     0.38,
  quality:        0.55,
  label:          'treadDark',
});

// Platform: woven at a different grain angle
api.surface.woven({
  amplitude:      0.20,
  threadSpacing:  3.8,
  threadWidth:    0.48,
  grainAngleDeg:  45,
  quality:        0.55,
  label:          'platform',
});

// Brass posts: diamond knurl grip
api.surface.knurl({
  style:     'diamond',
  profile:   'round',
  amplitude: 0.5,
  cellWidth: 2.8,
  sharpness: 2,
  quality:   0.55,
  label:     'rail',
});

// Bronze balusters: fine fuzzy roughness
api.surface.fuzzy({
  amplitude: 0.22,
  scale:     2.2,
  octaves:   2,
  quality:   0.5,
  label:     'baluster',
});

// Handrail: horizontal rib texture
api.surface.knurl({
  style:     'ribs',
  amplitude: 0.30,
  cellWidth: 3.5,
  quality:   0.5,
  label:     'handrail',
});

return stair;
